const sorted = data.conversations.sort((a,b) => b.lastContactTimeLong - a.lastContactTimeLong);

// Top 30 most recent
console.log('=== TOP 30 最近活跃会话 ===');
sorted.slice(0, 30).forEach((c, i) => {
  const daysAgo = ((now - c.lastContactTimeLong) / msPerDay).toFixed(1);
  const msgType = c.latestMessage ? c.latestMessage.messageType : '?';
  const content = c.latestMessage ? c.latestMessage.content.substring(0, 80) : '(none)';
  const unread = c.unreadCount > 0 ? ' [未读:' + c.unreadCount + ']' : '';
  console.log((i+1) + '. ' + c.name + ' | ' + c.complianceCountryCode + ' | ' + daysAgo + 'd ago | ' + msgType + unread);
  console.log('   ' + content);
});

// Count by message direction in last 7d
console.log('\n=== 7d内消息方向统计 ===');
let total7d = 0, received7d = 0, send7d = 0;
sorted.forEach(c => {
  const daysAgo = (now - c.lastContactTimeLong) / msPerDay;
  if (daysAgo <= 7) {
    total7d++;
    if (c.latestMessage && c.latestMessage.messageType === 'received') received7d++;
    if (c.latestMessage && c.latestMessage.messageType === 'send') send7d++;
  }
});
console.log('7d活跃总会话: ' + total7d);
console.log('最后一条是客户发: ' + received7d);
console.log('最后一条是我方发: ' + send7d);

// 24h active
console.log('\n=== 24h内活跃会话 ===');
let count24h = 0;
sorted.forEach(c => {
  const daysAgo = (now - c.lastContactTimeLong) / msPerDay;
  if (daysAgo <= 1) {
    count24h++;
    console.log(c.name + ' | ' + c.complianceCountryCode + ' | ' + c.latestMessage.messageType + ' | ' + (c.latestMessage ? c.latestMessage.content.substring(0, 100) : ''));
  }
});
console.log('Total 24h: ' + count24h);
"

