const fs = require('fs');
const path = require('path');
const chatDir = './data/chat_history';
const files = fs.readdirSync(chatDir).filter(f => f.endsWith('.json'));

// STATE.md says 7d active = 43. Let's check actual customer messages in last 7d
const now = Date.now();
const ms7d = 7 * 86400000;
let results = [];

files.forEach(f => {
  try {
    const data = JSON.parse(fs.readFileSync(path.join(chatDir, f), 'utf8'));
    const messages = data.messages || data.chatHistory || data.list || [];
    if (!Array.isArray(messages) && messages) {
      // try to find array
      for (const key of Object.keys(data)) {
        if (Array.isArray(data[key])) { messages = data[key]; break; }
      }
    }
    if (!Array.isArray(messages)) return;

    let lastCustMsg = null;
    let customerMsgs7d = 0;
    let ourMsgs7d = 0;

    messages.forEach(m => {
      const t = m.gmtChat || m.gmtCreate || m.sendTime || m.time || 0;
      const ts = typeof t === 'string' ? new Date(t).getTime() : (t < 10000000000 ? t * 1000 : t);
      if (!ts || isNaN(ts)) return;
      if (now - ts > ms7d) return;

      const type = m.messageType || m.direction || m.type || '';
      const isReceived = type === 'received' || type === 1 || type === 'customer';
      const isSend = type === 'send' || type === 0 || type === 'agent';

      if (isReceived) customerMsgs7d++;
      if (isSend) ourMsgs7d++;

      if (isReceived && (!lastCustMsg || ts > lastCustMsg.ts)) {
        lastCustMsg = { ts, content: (m.content || JSON.stringify(m)).substring(0, 120) };
      }
    });

    if (customerMsgs7d > 0 || ourMsgs7d > 0) {
      results.push({ name: data.name || f.replace('.json',''), file: f, customerMsgs7d, ourMsgs7d, lastCustMsg });
    }
  } catch(e) {}
});

results.sort((a,b) => b.customerMsgs7d - a.customerMsgs7d);
console.log('=== 7d内有客户回复的会话（按客户消息数排序）===');
results.forEach((r, i) => {
  if (r.customerMsgs7d > 0) {
    const lastTxt = r.lastCustMsg ? new Date(r.lastCustMsg.ts).toLocaleString('zh-CN') + ': ' + r.lastCustMsg.content : 'N/A';
    console.log((i+1) + '. ' + r.name + ' | 客户' + r.customerMsgs7d + '条/我方' + r.ourMsgs7d + '条');
    console.log('   最后客户消息: ' + lastTxt);
  }
});
console.log('\nTotal with customer msgs in 7d: ' + results.filter(r => r.customerMsgs7d > 0).length);
console.log('Total with any activity in 7d: ' + results.length);
"

