const fs = require('fs');
const path = require('path');

// Read chat histories for 5 key customers
const targets = [
  { name: 'Keinjol Tata', file: '2500000853693-3500001141060_11011_icbu.json' },
  { name: 'Christine Muwela', file: '1507541771655-2500000853693_11011_icbu.json' },
  { name: 'Esther Chola', file: '2500000853693-4500025203322_11011_icbu.json' },
  { name: 'arshavin amoah', file: '133605767280-2500000853693_11011_icbu.json' },
  { name: 'jonathan aston', file: '133167278119-2500000853693_11011_icbu.json' }
];

const FACTORY_UID = '2500000853693';

targets.forEach(t => {
  const fpath = path.join('data/chat_history', t.file);
  if (!fs.existsSync(fpath)) {
    console.log('=== ' + t.name + ' === FILE NOT FOUND: ' + t.file);
    console.log();
    return;
  }
  const d = JSON.parse(fs.readFileSync(fpath, 'utf8'));
  const msgs = d.messages || [];

  console.log('=== ' + t.name + ' | 总消息: ' + msgs.length + ' ===');

  // Show all messages in chronological order (oldest first)
  msgs.reverse(); // they're stored newest-first

  let ourCount = 0, custCount = 0, sysCount = 0;

  msgs.forEach((m, i) => {
    const msg = m.message;
    const content = msg.content;
    let text = '';
    if (content && content.text && content.text.content) {
      text = content.text.content;
    } else if (typeof content === 'string') {
      text = content;
    } else {
      // try custom card
      try {
        if (content && content.custom && content.custom.summary) {
          text = '[产品卡片: ' + content.custom.summary + ']';
        }
      } catch(e) {}
    }

    const sender = msg.sender;
    const senderId = sender ? (sender.uid || '').split('@')[0] : '';
    const isOurs = senderId === FACTORY_UID;

    const ext = msg.extension && msg.extension.basicMessageInfo;
    const isSys = ext ? (() => { try { return JSON.parse(ext).systemMessage; } catch(e) { return false; } })() : false;

    if (isSys) { sysCount++; return; }

    const ts = msg.createAt;
    const date = ts ? new Date(ts).toLocaleString('zh-CN', {month:'numeric',day:'numeric',hour:'2-digit',minute:'2-digit'}) : '?';

    if (isOurs) {
      ourCount++;
      console.log('  [' + date + '] 我方: ' + text.substring(0, 200));
    } else {
      custCount++;
      console.log('  [' + date + '] 客户: ' + text.substring(0, 200));
    }
  });

  console.log('  统计: 客户' + custCount + '条 / 我方' + ourCount + '条 / 系统' + sysCount + '条');

  // Critical check: last customer message and last our message
  console.log();
});
