const fs = require('fs');
const { Document, Packer, Paragraph, TextRun, HeadingLevel, Table, TableRow, TableCell, WidthType, BorderStyle, ShadingType, PageBreak } = require('docx');

// ========== 工具函数 ==========
function headerCell(text, width, color = '1a5276') {
  return new TableCell({
    width: { size: width, type: WidthType.PERCENTAGE },
    shading: { type: ShadingType.SOLID, color },
    children: [new Paragraph({ children: [new TextRun({ text, bold: true, color: 'FFFFFF', size: 20, font: 'Microsoft YaHei' })], spacing: { before: 30, after: 30 } })],
  });
}

function cell(text, width, opts = {}) {
  return new TableCell({
    width: { size: width, type: WidthType.PERCENTAGE },
    children: [new Paragraph({ children: [new TextRun({ text, size: 19, font: 'Microsoft YaHei', ...opts })], spacing: { before: 25, after: 25 } })],
  });
}

function multiCell(lines, width) {
  return new TableCell({
    width: { size: width, type: WidthType.PERCENTAGE },
    children: lines.map(l => new Paragraph({ children: [new TextRun({ text: l, size: 18, font: 'Microsoft YaHei' })], spacing: { before: 20, after: 20 } })),
  });
}

function heading(text, level) {
  const sizes = { 1: 32, 2: 26, 3: 22 };
  return new Paragraph({ heading: level, children: [new TextRun({ text, bold: true, font: 'Microsoft YaHei', size: sizes[level] || 22 })], spacing: { before: 200, after: 100 } });
}

function para(text, opts = {}) {
  return new Paragraph({ children: [new TextRun({ text, size: 21, font: 'Microsoft YaHei', ...opts })], spacing: { before: 60, after: 60 } });
}

function redPara(text) {
  return para(`⚠️ ${text}`, { color: 'c0392b', bold: true });
}

function scriptBox(scriptText) {
  return new Paragraph({
    children: [new TextRun({ text: scriptText, size: 20, font: 'Microsoft YaHei', italics: true, color: '2c3e50' })],
    spacing: { before: 60, after: 60 },
    border: { top: { style: BorderStyle.SINGLE, size: 2, color: '2980b9' }, bottom: { style: BorderStyle.SINGLE, size: 2, color: '2980b9' }, left: { style: BorderStyle.SINGLE, size: 2, color: '2980b9' }, right: { style: BorderStyle.SINGLE, size: 2, color: '2980b9' } },
  });
}

function sectionHeader(text) {
  return heading(text, 1);
}

// ========== 构建文档 ==========
const children = [];

// ========== 封面 ==========
children.push(new Paragraph({ spacing: { before: 2000 } }));
children.push(new Paragraph({ heading: HeadingLevel.HEADING_1, alignment: 'center', children: [new TextRun({ text: 'OKKI 客户分析日报', bold: true, font: 'Microsoft YaHei', size: 48, color: '1a5276' })], spacing: { after: 200 } }));
