const fs = require('fs');
const path = require('path');
const FACTORY_UID = '2500000853693';

const targets = [
  { name: 'Inderpreet kaur', file: '2500000853693-4500009648245_11011_icbu.json' },
  { name: 'Rosette Ngoy', file: '2500000853693-4500008871706_11011_icbu.json' },
  { name: 'diego vargas', file: '2500000853693-5500014894268_11011_icbu.json' },
  { name: 'Clara ElAssaad', file: '2500000853693-5500015922947_11011_icbu.json' },
  { name: 'Brian Robert Ocholi', file: '1507647213228-2500000853693_11011_icbu.json' }
];

const chatDir = 'data/chat_history';

targets.forEach(t => {
  const fpath = path.join(chatDir, t.file);
  console.log('========== ' + t.name + ' ==========');
  if (!fs.existsSync(fpath)) {
    console.log('FILE NOT FOUND: ' + t.file);
    console.log();
    return;
  }
  const d = JSON.parse(fs.readFileSync(fpath, 'utf8'));
  const msgs = [...(d.messages || [])].reverse();

  let custMsgs = 0, ourMsgs = 0, sysMsgs = 0;
  let lastCustDate = '', lastOurDate = '', lastCustContent = '', lastOurContent = '';

  msgs.forEach(m => {
    const msg = m.message;
    const ext = msg.extension && msg.extension.basicMessageInfo;
    const isSys = ext ? (() => { try { return JSON.parse(ext).systemMessage || JSON.parse(ext).autoReply; } catch(e) { return false; } })() : false;
    if (isSys) { sysMsgs++; return; }

    let text = '';
    if (msg.content && msg.content.text && msg.content.text.content) {
      text = msg.content.text.content;
    } else if (typeof msg.content === 'string') {
      text = msg.content;
    }
    if (!text) return;

    const senderId = (msg.sender && msg.sender.uid || '').split('@')[0];
    const isOurs = senderId === FACTORY_UID;
    const ts = msg.createAt;
    const date = ts ? new Date(ts).toLocaleString('zh-CN', {month:'numeric',day:'numeric',hour:'2-digit',minute:'2-digit'}) : '?';

    if (isOurs) {
      ourMsgs++;
      lastOurDate = date;
      lastOurContent = text;
      console.log('  [' + date + '] 我方: ' + text.substring(0, 200));
    } else {
      custMsgs++;
      lastCustDate = date;
      lastCustContent = text;
      console.log('  [' + date + '] 客户: ' + text.substring(0, 200));
    }
  });

  // Summary
  const daysSinceCust = lastCustDate ? Math.round((Date.now() - new Date(msgs.find(m => {
    const sid = (m.message.sender && m.message.sender.uid || '').split('@')[0];
    return sid !== FACTORY_UID;
  })?.message?.createAt || Date.now()).getTime()) / 86400000) : '?';

  console.log('---');
  console.log('客户' + custMsgs + '条 / 我方' + ourMsgs + '条 / 系统' + sysMsgs + '条');
  console.log('最后客户: [' + lastCustDate + '] ' + lastCustContent.substring(0, 100));
  console.log('最后我方: [' + lastOurDate + '] ' + lastOurContent.substring(0, 100));
  console.log();
});
